 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { NodeNetworkStateModelRef } from '@models';
 5	import { Button, Toolbar, ToolbarContent, ToolbarGroup, ToolbarItem } from '@patternfly/react-core';
 6	import { ListIcon } from '@patternfly/react-icons';
 7	import TechPreview from '@utils/components/TechPreview/TechPreview';
 8	
 9	import TopologyToolbarFilter from './TopologyToolbarFilter';
10	
11	import './TopologyToolbar.scss';
12	
13	type TopologyToolbarProps = {
14	  selectedNodeFilters: string[];
15	  setSelectedNodeFilters: Dispatch<SetStateAction<string[]>>;
16	  nodeNames: string[];
17	};
18	
19	const TopologyButton: FC<TopologyToolbarProps> = (props) => {
20	  const navigate = useNavigate();
21	  const setSelectedNodeFilters = props.setSelectedNodeFilters;
22	
23	  return (
24	    <Toolbar className="topology-toolbar" clearAllFilters={() => setSelectedNodeFilters([])}>
25	      <ToolbarContent className="topology-toolbar__content">
26	        <ToolbarGroup>
27	          <TopologyToolbarFilter {...props} />
28	          <TechPreview />
29	        </ToolbarGroup>
30	        <ToolbarGroup>
31	          <ToolbarItem className="list-view-btn">
32	            <Button
33	              isInline
34	              variant="plain"
35	              onClick={() => navigate(`/k8s/cluster/${NodeNetworkStateModelRef}`)}
36	            >
37	              <ListIcon />
38	            </Button>
39	          </ToolbarItem>
40	        </ToolbarGroup>
41	      </ToolbarContent>
42	    </Toolbar>
43	  );
44	};
45	
46	export default TopologyButton;

